        final AgentSpan span = scope.span();
        DECORATE.onError(span, throwable);
        DECORATE.beforeFinish(span);
        span.finish();
      } finally {
        scope.close();
        CallDepthThreadLocalMap.reset(com.google.gson.Gson.class);
      }
    }
  }

